+
+namespace Poco {
+
+
+void EnvironmentImpl::nodeIdImpl(NodeId& id)
+{
+	struct ifreq ifr;
+
+	int s = socket(PF_INET, SOCK_DGRAM, 0);
+	if (s == -1) throw SystemException("cannot open socket");
+
+	std::strcpy(ifr.ifr_name, "eth0");
+	int rc = ioctl(s, SIOCGIFHWADDR, &ifr);
