+void File::renameTo(const std::string& path)
+{
+	renameToImpl(path);
+	setPathImpl(path);
+}
+
+	
+void File::remove(bool recursive)
+{
+	if (recursive && !isLink() && isDirectory())
+	{
+		std::vector<File> files;
+		list(files);
+		for (std::vector<File>::iterator it = files.begin(); it != files.end(); ++it)
+		{
+			it->remove(true);
+		}
+	}
+	removeImpl();
+}
