+
+void File::createDirectories()
+{
+	if (!exists())
+	{
+		Path p(getPathImpl());
+		p.makeDirectory();
+		if (p.depth() > 1)
+		{
+			p.makeParent();
+			File f(p);
+			f.createDirectories();
+		}
+		createDirectoryImpl();
+	}
+}
