+
+void File::list(std::vector<std::string>& files) const
+{
+	files.clear();
+	DirectoryIterator it(*this);
+	DirectoryIterator end;
+	while (it != end)
+	{
+		files.push_back(it.name());
+		++it;
+	}
+}
+
+
+void File::list(std::vector<File>& files) const
