+
+Path& Path::makeParent()
+{
+	if (_name.empty())
+	{
+		if (_dirs.empty())
+		{
+			if (!_absolute)
+				_dirs.push_back("..");
+		}
+		else
+		{
+			if (_dirs.back() == "..")
+				_dirs.push_back("..");
+			else
+				_dirs.pop_back();
+		}
+	}
+	else
+	{
+		_name.clear();
+		_version.clear();
+	}
+	return *this;
+}
