+
+Path& Path::resolve(const Path& path)
+{
+	if (path.isAbsolute())
+	{
+		assign(path);
+	}
+	else
+	{
+		for (int i = 0; i < path.depth(); ++i)
+			pushDirectory(path[i]);
+		_name = path._name;
+	}
+	return *this;
+}
