+void Path::pushDirectory(const std::string& dir)
+{
+	if (!dir.empty() && dir != ".")
+	{
+#if defined(POCO_OS_FAMILY_VMS)
+		if (dir == ".." || dir == "-")
+		{
+			if (!_dirs.empty() && _dirs.back() != ".." && _dirs.back() != "-")
+				_dirs.pop_back();
+			else if (!_absolute)
+				_dirs.push_back(dir);
+		}
+		else _dirs.push_back(dir);
+#else
+		if (dir == "..")
+		{
+			if (!_dirs.empty() && _dirs.back() != "..")
+				_dirs.pop_back();
+			else if (!_absolute)
+				_dirs.push_back(dir);
+		}
+		else _dirs.push_back(dir);
+#endif
+	}
+}
