+bool Path::find(StringVec::const_iterator it, StringVec::const_iterator end, const std::string& name, Path& path)
+{
+	while (it != end)
+	{
+		Path p(*it);
+		p.makeDirectory();
+		p.resolve(Path(name));
+		File f(p);
+		if (f.exists())
+		{
+			path = p;
+			return true;
+		}
+		++it;
+	}
+	return false;
+}
