+void* SharedLibraryImpl::findSymbolImpl(const std::string& name)
+{
+	FastMutex::ScopedLock lock(_mutex);
+
+	void* result = 0;
+	if (_handle && shl_findsym(&_handle, name.c_str(), TYPE_UNDEFINED, &result) !=  -1)
+		return result;
+	else
+		return 0;
