+bool SharedLibraryImpl::isLoadedImpl() const
+{
+	return _handle != 0; 
+}
+
+
+void* SharedLibraryImpl::findSymbolImpl(const std::string& name)
+{
+	FastMutex::ScopedLock lock(_mutex);
+
+	void* result = 0;
+	if (_handle)
+	{
+		result = dlsym(_handle, name.c_str());
+	}
+	return result;
+}
