+	#if defined(_DEBUG)
+		return "d.dll";
+	#else
+		return ".dll";
+	#endif
+#else
+	#if defined(_DEBUG)
+		return "d.so";
+	#else
+		return ".so";
+	#endif
+#endif
+}
